def filtrar_acima(valores, limite):
    saida = []
    for valor in valores:
        if valor > limite:
            saida.append(valor)
    return saida

print(filtrar_acima([10, 80, 55, 20], 50))

def aplicar_reajuste(valores, taxa):
    reajustados = []
    for valor in valores:
        reajustados.append(valor * (1 + taxa))
    return reajustados

print(aplicar_reajuste([100.0, 200.0], 0.1))

def contar_criticos(valores, limite):
    total = 0
    for valor in valores:
        if valor >= limite:
            total += 1
    return total

print(contar_criticos([30, 70, 90, 40], 70))
